{
  "name": "Health First Colorado Buy-In (QMB, SLMB, QI)",
  "eligibility": {
    "age": 65,
    "income_limits": "These are federal Medicare Savings Programs (MSPs) administered through Health First Colorado. Exact 2026 dollar amounts not in search results; limits vary by tier (QMB, SLMB, QI) and are typically 100% FPL for QMB, 120% for SLMB, 135% for QI, adjusted annually for household size. Contact county office for current table as general Health First Colorado limits (e.g., family of 1: up to $1,735 adults) do not apply directly[1][4].",
    "asset_limits": "There are three levels of MSP depending on income and asset limits; specific 2026 asset thresholds (often ~$9,090 individual/$13,630 couple, excluding home, car, etc.) not detailed in results. What counts: countable assets like bank accounts; exempt: primary home, one vehicle, personal belongings[1].",
    "other_requirements": ["Must be enrolled in Medicare Part A and B", "Colorado resident", "U.S. citizen or qualified immigrant", "For elderly loved ones: age 65+ or disabled under 65 qualifying for Medicare"]
  },
  "benefits": {
    "type": "financial",
    "value": "**QMB:** Pays Medicare Part B monthly premium, deductibles, copays, coinsurance (covers the 20% Medicare does not, providing full coverage). **SLMB & QI-1:** Pays Part B monthly premium only; responsible for deductibles, copays, coinsurance (supplemental plans may fill gaps)[1].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://www.healthfirstcolorado.com/apply-now/", "Phone: Contact local county Human Services office (numbers via https://cdhs.colorado.gov/counties)", "Mail or in-person: Local county Department of Human Services office"],
    "processing_time": "Not specified in results",
    "waitlist": "QI often has federal funding caps and waitlists; others generally no waitlist[1]",
    "forms": ["Health First Colorado application (no specific MSP form named; apply via standard Medicaid portal)"],
    "documents": ["Proof of income", "Proof of assets", "Medicare enrollment proof (Part A/B cards)", "ID, residency proof", "Social Security number"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available through all Colorado counties",
    "regional_variations": "Administered by county Human Services offices; potential processing differences by county but program uniform[1]",
    "offices_or_providers": ["Local county Department of Human Services offices"]
  },
  "official_source": "https://hcpf.colorado.gov (search Medicare Savings Programs or contact for MSP details); apply at https://www.healthfirstcolorado.com/apply-now/[1][2]",
  "gotchas": ["Not full Medicaid—only Medicare cost-sharing assistance; does not cover long-term care or services beyond Medicare gaps", "QI has limited federal slots and potential waitlist", "Must already have Medicare; auto-enrollment not guaranteed", "Asset test applies (often overlooked vs. income-only programs)", "Three distinct tiers with different income/asset cutoffs—check exact level", "If in Working Adults with Disabilities Buy-In, different rules (premiums $0-$200 based on income, full Medicaid services)[2]"],
  "data_shape_notes": "Tiered by QMB/SLMB/QI with escalating income limits and decreasing benefit levels; asset-tested unlike some Medicaid; funding-capped for QI; separate from disability Buy-In programs which offer full Health First Colorado services for premium"
}

{
  "name": "Colorado SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to anyone eligible for Medicare (typically age 65+ or under 65 with certain disabilities), family members, caregivers, and those soon to be eligible[1][2][3]",
    "asset_limits": "No asset limits or tests apply[1]",
    "other_requirements": ["Must be Medicare-eligible or soon eligible; family/caregivers of Medicare beneficiaries also qualify[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling and education on Medicare options (Parts A, B, C, D, Medigap), enrollment, appeals, coordinating benefits, prescription drug help, applying for low-income programs like Extra Help/LIS or Medicare Savings Programs; outreach presentations; no insurance sales[1][2][3][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-888-696-7213 (toll-free, 8:30 am - 4:30 pm); Spanish: 303-894-5953; Website: https://doi.colorado.gov/insurance-products/health-insurance/senior-health-care (Colorado DOI SHIP page); Email: Brandon.D.Davis@state.co.us; In-person or local counseling via state network (contact phone for appointment)[4][5]"],
    "processing_time": "No formal application processing; counseling available upon contact, typically by appointment[1][7]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist with Medicare-related forms during sessions[2]"],
    "documents": ["Medicare card (if available), prescription list, provider/pharmacy info, health conditions/procedures, income/asset details, other insurance info, questions about Medicare[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; statewide coverage[4][5]",
    "regional_variations": "Delivered through local area agencies on aging and community partners; access via central phone statewide, potential local offices/providers but no specified differences in services or wait times[2][5]",
    "offices_or_providers": ["Primary: Department of Regulatory Agencies, 1560 Broadway Suite 850, Denver CO 80202; local network of over 2,200 sites nationally, including Colorado partners[2][4]"]
  },
  "official_source": "https://doi.colorado.gov/insurance-products/health-insurance/senior-health-care",
  "gotchas": ["Counselors do not sell insurance and provide unbiased advice only—not agents; contact 3 months before Medicare starts for best help; not a direct financial benefit but assistance accessing other programs; training ensures expertise but services are advisory, not healthcare provision[1][3]"],
  "data_shape_notes": "no income/asset test; open to Medicare-eligible and families statewide; service-based counseling via phone statewide with local delivery network; no formal application or waitlist"
}

{
  "name": "Meals on Wheels Colorado",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits statewide; some providers use sliding scale fees based on income (e.g., Fort Collins: reduced fees with gross monthly income verification, max $6.50-$7.50/meal). Broomfield: any income level. No specific dollar amounts or household tables provided.",
    "asset_limits": "No asset limits mentioned across providers.",
    "other_requirements": ["Homebound or unable to shop/prepare meals safely", "Some allow under 60 with disability proof or medical referral (e.g., Fort Collins age 62+ or disability; Broomfield under 60 with referral)", "Lives alone or with caregiving family in some areas (e.g., Broomfield)", "Assessed as needing service"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious meals providing at least 1/3 of daily nutrients (entree, vegetables, fruits, bread, milk); hot meals weekdays (e.g., Broomfield 11am-12:30pm Mon-Fri); frozen weekend meals in some areas; no fixed hours/week but typically daily delivery; suggested donations $2-$7.50/meal but no one denied for inability to pay.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: VOA Denver metro/Adams/Arapahoe/Clear Creek/Denver/Douglas/Gilpin/Jefferson 303-294-0111; Larimer 970-472-9630; Broomfield via senior services (number not specified); Fort Collins via website; Mesa County phone/office; Coal Creek (Lafayette/Louisville/Erie/Superior) 303-665-0566", "Email: mdeherrera@voacolorado.org (Denver area), larimer@voacolorado.org, mtrejo@voacolorado.org", "Online: mealsonwheelsfc.org (Fort Collins), coalcreekmow.org (some areas)", "Mail/In-person: Application mailed or downloaded (Mesa County); short phone intake (Broomfield)"],
    "processing_time": "Within 24 business hours (Broomfield); office call after application (Mesa County)",
    "waitlist": "Possible longer wait due to application influx (Mesa County); varies by region",
    "forms": ["Home Delivered Meal application (Mesa County downloadable)", "Congregate Intake Form (Mesa County)", "Short phone intake (Broomfield)"],
    "documents": ["Proof of disability if under age requirement", "Gross monthly income verification for reduced fees (some areas)", "Medical referral if under 60", "Name, address, phone for initial contact"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "County-specific providers; not uniform across all Colorado counties",
    "regional_variations": "Multiple independent providers with differing ages (60 vs 62), fees ($3.50 suggested Mesa, $4 hot/$2 frozen Broomfield), contacts, and wait times; VOA covers Adams/Arapahoe/Clear Creek/Denver/Douglas/Gilpin/Jefferson/Larimer; Fort Collins separate (62+); Broomfield own program; Mesa County donation-based; Coal Creek for Lafayette/Louisville/Erie/Superior",
    "offices_or_providers": ["VOA Colorado (Denver metro counties)", "Meals on Wheels Fort Collins", "Broomfield Senior Services", "Meals on Wheels Mesa County", "Coal Creek Meals on Wheels"]
  },
  "official_source": "No single statewide .gov site; primary network via mealsonwheelsamerica.org/find-meals-and-services/",
  "gotchas": ["Not a single unified program—must contact specific county/provider; no one denied for inability to pay but contributions requested; varies by exact location (e.g., age 60 vs 62, homebound assessment required); waitlists in high-demand areas; changes/cancellations need 24hr notice; caregivers may qualify if co-residing in some areas"],
  "data_shape_notes": "Decentralized by county/provider with no uniform eligibility/fees; regionally fragmented providers, no income test but sliding donations; homebound focus with exceptions for disability/referral"
}

