{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of federal poverty level. Example limits (from a 2024 application form, subject to annual updates based on federal poverty guidelines): 1-person household: $18,825; 2-person: $25,550; 3-person: $32,725; 4-person: $39,000; 5-person: $45,725. Contact local provider for current table by household size.",
    "asset_limits": "No asset limits mentioned in program guidelines.",
    "other_requirements": ["Unemployed", "U.S. work authorization (implied)", "Willing to participate in occupational skills training and job search assistance", "Reside in a county served by the local SCSEP provider"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time work-based training (average 20 hours/week) at community service sites (e.g., child care, customer service, teachers' aide, computer technician, building maintenance, health care). Paid the highest of federal, state, or local minimum wage. Training lasts about 6 months, followed by assistance to find unsubsidized permanent employment. Support services like job search assistance.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local SCSEP provider (e.g., SER National for Colorado: no direct phone/URL in results, use national locator via dol.gov or state workforce agency)", "In-person or phone at local grantee office", "Waiting list applications (e.g., PDF forms from providers like A4TD)"],
    "processing_time": "Not specified; if eligible and no waitlist, enrolled promptly.",
    "waitlist": "Common; some providers actively accepting waiting list applications.",
    "forms": ["SCSEP Waiting List Application (example from providers)"],
    "documents": ["Proof of age", "Proof of income (all household sources counted)", "Proof of unemployment duration", "County of residence", "Contact info (phone, email)", "Veteran status if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must reside in a county served by the local SCSEP grantee/provider.",
    "regional_variations": "Operated by different grantees (e.g., SER National serves Colorado in over 225 counties across multiple states, including CO; other national non-profits or state agencies may operate in specific areas). Wait times and availability vary by region and provider. Enrollment priority given first to veterans/qualified spouses, then those 65+, with disabilities, rural residents, etc.",
    "offices_or_providers": ["SER National (covers Colorado)", "Other DOL grantees (19 national non-profits and state agencies; locate via local workforce office or dol.gov)"]
  },
  "official_source": "https://www.dol.gov/agencies/eta/seniors",
  "gotchas": ["Income calculated for full family household at 125% FPL (contact provider to confirm exact amount and what counts)", "Priority enrollment tiers may delay non-priority applicants (veterans first, then 65+, disabled, rural, etc.)", "Temporary training program (avg. 6 months) aimed at unsubsidized job placement, not permanent employment", "Must be unemployed and seeking training to bridge to work; not general welfare", "Availability and waitlists vary by county/provider—check local office", "Residency restricted to provider's service counties"],
  "data_shape_notes": "Federally uniform but locally administered by grantees like SER National in CO; income scales by household size at 125% FPL (annual updates); priority tiers affect access; county-restricted by provider coverage; waitlists common"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident of a skilled nursing home or licensed assisted living residence in Colorado (or a relative, friend, facility staff, or concerned community member acting on their behalf). Services are resident-directed."][2][7]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including receiving and resolving complaints on quality of care, use of restraints, transfers/discharges, abuse, violations of rights (e.g., privacy, dignity, poor staff attitudes), medication issues, hygiene, call lights; problem-solving, mediation, investigation; confidential and resident-directed support. No financial aid, hours, or fixed dollar amounts provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Visit https://www.coombudsman.org and use 'Find an Ombudsman' to locate and contact the local office by region.", "Phone regional offices (e.g., Boulder County: 303-441-1170; Pueblo County: 719-601-6282; State Volunteer Coordinator: 720-925-8609).", "Email regional contacts (e.g., ecorson@bouldercounty.gov for Boulder; dmason@srda.org for Pueblo; jesse.bond@state.co.us for state inquiries).", "In-person or facility visits by local ombudsmen (no formal application for recipients; contact to report issues)."],
    "processing_time": "Immediate response upon contact; no formal processing as it's complaint-driven advocacy, not an enrollment program.",
    "waitlist": null,
    "forms": ["No specific forms required for receiving services; applications only for volunteers."],
    "documents": ["No documents needed; services are accessible by phone or visit. Provide details of the concern or facility name."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of licensed skilled nursing homes and assisted living facilities in Colorado.",
    "regional_variations": "Network of local offices with different providers and contacts (e.g., Boulder County via Community Services; Pueblo via SRDA). Visit frequency may vary (e.g., nursing homes weekly, assisted living bi-monthly in Boulder).",
    "offices_or_providers": ["State site: https://www.coombudsman.org (Find an Ombudsman).", "Boulder: Erica Corson, 303-441-1170.", "Pueblo: SRDA, 719-601-6282."]
  },
  "official_source": "https://www.coombudsman.org",
  "gotchas": ["Not a healthcare or financial aid program—purely advocacy for rights and complaints in licensed facilities only (excludes non-licensed care like adult foster homes).", "Services are confidential and resident-directed, so family may need resident consent.", "Anyone can contact (not just residents), but focus is on facility residents.", "Volunteering requires training/background check, often confused with receiving services."],
  "data_shape_notes": "no income/asset test; advocacy-only for licensed long-term care residents; delivered via regional offices statewide; complaint-driven, not enrollment-based"
}

